        existingAppointment.setRecurring(appointmentDTO.isRecurring());
        existingAppointment.setRecurrencePattern(appointmentDTO.getRecurrencePattern());
        existingAppointment.setSimpleSummary(appointmentDTO.getSimpleSummary());
        existingAppointment.setUpdatedAt(LocalDateTime.now());

        Appointment updatedAppointment = appointmentService.updateAppointment(id, existingAppointment);
        return ResponseEntity.ok(convertToDTO(updatedAppointment));
    }

