private final PrescriptionPdfService prescriptionPdfService;
private final NotificationFeignClient notificationFeignClient;
private final PatientFeignClient patientFeignClient;

private final PrescriptionPdfService prescriptionPdfService;
private final NotificationFeignClient notificationFeignClient;
private final PatientFeignClient patientFeignClient;

// ========== PDF DOWNLOAD ==========

/**
 * GET /api/prescriptions/{id}/pdf
 * Downloads the generated PDF as a byte stream
 */
@GetMapping("/{id}/pdf")
public ResponseEntity<byte[]> downloadPdf(@PathVariable String id) {
    log.info("Downloading PDF for prescription ID: {}", id);
    byte[] pdfBytes = prescriptionPdfService.generatePdf(id);

    HttpHeaders headers = new HttpHeaders();
    headers.setContentType(MediaType.APPLICATION_PDF);
    headers.setContentDispositionFormData("attachment", "prescription-" + id + ".pdf");
    headers.setContentLength(pdfBytes.length);

    return new ResponseEntity<>(pdfBytes, headers, HttpStatus.OK);
}

// ========== SEND PDF VIA EMAIL ==========

/**
 * POST /api/prescriptions/{id}/send-pdf
 * Generates PDF, base64-encodes it, and sends it to patient via notification service
 */
@PostMapping("/{id}/send-pdf")
public ResponseEntity<Void> sendPdfToPatient(@PathVariable String id) {
    log.info("Sending PDF for prescription ID: {}", id);

    try {
        // Generate PDF
        byte[] pdfBytes = prescriptionPdfService.generatePdf(id);
        String pdfBase64 = Base64.getEncoder().encodeToString(pdfBytes);

        // Fetch prescription to get patient and doctor info
        PrescriptionResponseDTO prescription = mapper.toResponse(prescriptionService.getPrescriptionById(id));

        // Fetch patient email
        PatientSimpleDTO patient = patientFeignClient.getPatientById(prescription.getPatient().getUserId());

        // Build email request
        PdfEmailRequest emailRequest = PdfEmailRequest.builder()
                .patientEmail(patient.getEmail())
                .patientName(patient.getName())
                .doctorName(prescription.getDoctor().getName())
                .prescriptionId(id)
                .pdfBase64(pdfBase64)
                .build();

        // Send to notification service
        notificationFeignClient.sendPrescriptionEmail(emailRequest);

        log.info("PDF sent successfully for prescription ID: {}", id);
        return ResponseEntity.noContent().build();

    } catch (Exception e) {
        log.error("Failed to send PDF for prescription ID {}: {}", id, e.getMessage(), e);
        throw new RuntimeException("Failed to send prescription PDF: " + e.getMessage(), e);
    }
}

