private String calculateDuration(LocalDate dateDebut, LocalDate dateFin) {
    if (dateDebut == null || dateFin == null) {
        return null;
    }
    long days = java.time.temporal.ChronoUnit.DAYS.between(dateDebut, dateFin);
    return days + " days";
}

